import boto3

def create_sns_subscription(topic, endpoint):
    sns_client = boto3.client('sns')
    try:
        response = sns_client.subscribe(
            TopicArn=topic,
            Protocol='https',
            Endpoint=endpoint
        )
        print(f"Subscription ARN: {response['SubscriptionArn']}")
    except Exception as e:
        print(f"Error creating subscription: {e}")

def main():
    topic = input("Enter the SNS Topic ARN: ")
    endpoint = input("Enter the subscription endpoint (URL): ")
    create_sns_subscription(topic, endpoint)

if __name__ == "__main__":
    main()